// Set up the API key and base URL for OpenWeatherMap API
const apiKey = 'YOUR_API_KEY';
const baseUrl = 'https://api.openweathermap.org/data/2.5/forecast';

// Function to fetch weather data for a given city
async function fetchWeather(city) {
    try {
        const response = await fetch(`${baseUrl}?q=${city}&appid=${apiKey}&units=metric`);
        if (!response.ok) throw new Error('City not found or invalid API key');
        const data = await response.json();
        return data;
    } catch (error) {
        console.error('Error fetching weather data:', error.message);
        return null;
    }
}

// Function to parse and format the weather data
function formatForecast(data) {
    const forecast = [];
    const days = new Set();
    const dailyData = data.list.filter(item => {
        const date = new Date(item.dt * 1000);
        const day = date.toDateString().split(' ')[0];
        if (!days.has(day)) {
            days.add(day);
            return true;
        }
        return false;
    });

    dailyData.forEach(item => {
        const date = new Date(item.dt * 1000);
        const temp = item.main.temp;
        const feelsLike = item.main.feels_like;
        const precipitation = item.pop * 100;
        forecast.push({
            date: date.toDateString(),
            high: temp,
            low: feelsLike,
            precipitation: precipitation.toFixed(1) + '%'
        });
    });

    return forecast;
}

// Function to display the forecast
function displayForecast(forecast) {
    console.log('5-Day Weather Forecast:');
    forecast.forEach(day => {
        console.log(`Date: ${day.date}, High: ${day.high}°C, Low: ${day.low}°C, Precipitation: ${day.precipitation}`);
    });
}
